'use client';

import { useEffect } from 'react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/dist/ScrollTrigger';

export default function Animations() {
  useEffect(() => {
    gsap.registerPlugin(ScrollTrigger);

    // ── Cursor ──────────────────────────────────────────────────────
    const dot = document.getElementById('cursorDot');
    const ring = document.getElementById('cursorRing');
    let mouseX = 0, mouseY = 0;
    let ringX = 0, ringY = 0;

    const handleMouseMove = (e: MouseEvent) => {
      mouseX = e.clientX;
      mouseY = e.clientY;
      if (dot) {
        dot.style.left = mouseX + 'px';
        dot.style.top  = mouseY + 'px';
      }
    };

    document.addEventListener('mousemove', handleMouseMove);

    function animateRing() {
      ringX += (mouseX - ringX) * 0.12;
      ringY += (mouseY - ringY) * 0.12;
      if (ring) {
        ring.style.left = ringX + 'px';
        ring.style.top  = ringY + 'px';
      }
      requestAnimationFrame(animateRing);
    }
    animateRing();

    // ── Nav scroll ──────────────────────────────────────────────────
    const nav = document.getElementById('nav');
    const handleScroll = () => {
      if (nav) {
        nav.classList.toggle('scrolled', window.scrollY > 60);
      }
    };
    window.addEventListener('scroll', handleScroll);

    // ── Progress bar ────────────────────────────────────────────────
    const bar = document.getElementById('progressBar');
    const handleProgressScroll = () => {
      if (bar) {
        const pct = window.scrollY / (document.body.scrollHeight - window.innerHeight) * 100;
        bar.style.width = pct + '%';
      }
    };
    window.addEventListener('scroll', handleProgressScroll);

    // ── Hero entrance ────────────────────────────────────────────────
    const tl = gsap.timeline({ delay: 0.2 });
    tl.from('.hero-eyebrow', { opacity: 0, y: 20, duration: 0.7, ease: 'power3.out' })
      .from('.hero-title .line-inner', {
        yPercent: 110, duration: 0.9, ease: 'power3.out', stagger: 0.12
      }, '-=0.4')
      .from('.hero-sub', { opacity: 0, y: 16, duration: 0.7, ease: 'power3.out' }, '-=0.5')
      .from('.hero-actions > *', { opacity: 0, y: 12, duration: 0.6, ease: 'power3.out', stagger: 0.1 }, '-=0.4')
      .from('.hero-scroll-hint', { opacity: 0, duration: 0.5 }, '-=0.2');

    // ── Scroll reveals ───────────────────────────────────────────────
    gsap.utils.toArray('.reveal').forEach((el: any) => {
      gsap.from(el, {
        opacity: 0, y: 30,
        duration: 0.9,
        ease: 'power3.out',
        scrollTrigger: {
          trigger: el,
          start: 'top 85%',
          toggleActions: 'play none none none'
        }
      });
    });

    // ── Workflow sticky scroll ────────────────────────────────────────
    const totalSteps = 5;
    const stepEls = document.querySelectorAll('.workflow-step');
    const termTitle = document.getElementById('termTitle');
    const stepTitles = [
      'claude — pull token inventory',
      'figma-console-mcp — write variables',
      'figma_execute — generate components',
      'figma variables — add your sauce',
      'claude — push to code'
    ];

    function activateStep(idx: number) {
      stepEls.forEach((s, i) => s.classList.toggle('active', i === idx));
      document.querySelectorAll('.step-visual').forEach((v, i) => {
        v.classList.toggle('active', i === idx);
      });
      if (termTitle) {
        termTitle.textContent = stepTitles[idx];
      }
    }

    ScrollTrigger.create({
      trigger: '#workflow',
      start: 'top top',
      end: 'bottom bottom',
      scrub: false,
      onUpdate: self => {
        const idx = Math.min(
          Math.floor(self.progress * totalSteps),
          totalSteps - 1
        );
        activateStep(idx);
      }
    });

    // ── Loop ring rotate ─────────────────────────────────────────────
    gsap.to('.loop-ring', {
      rotation: 360,
      duration: 40,
      repeat: -1,
      ease: 'none'
    });

    // Keep nodes upright as ring spins
    gsap.to('.loop-node', {
      rotation: -360,
      duration: 40,
      repeat: -1,
      ease: 'none'
    });

    // ── Sauce tokens stagger ─────────────────────────────────────────
    ScrollTrigger.create({
      trigger: '.sauce-tokens',
      start: 'top 80%',
      onEnter: () => {
        gsap.from('.token-card', {
          opacity: 0, y: 20, scale: 0.96,
          duration: 0.5,
          ease: 'power3.out',
          stagger: 0.07
        });
      }
    });

    // ── Flow cards stagger ───────────────────────────────────────────
    ScrollTrigger.create({
      trigger: '.flow-diagram',
      start: 'top 75%',
      onEnter: () => {
        gsap.from('.flow-card', {
          opacity: 0, x: -20,
          duration: 0.5,
          ease: 'power3.out',
          stagger: 0.1
        });
      }
    });

    // ── Hero grid parallax ───────────────────────────────────────────
    gsap.to('.hero-grid', {
      yPercent: 30,
      ease: 'none',
      scrollTrigger: {
        trigger: '.hero',
        start: 'top top',
        end: 'bottom top',
        scrub: true
      }
    });

    gsap.to('.hero-glow', {
      yPercent: 50,
      ease: 'none',
      scrollTrigger: {
        trigger: '.hero',
        start: 'top top',
        end: 'bottom top',
        scrub: true
      }
    });

    // Cleanup
    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('scroll', handleScroll);
      window.removeEventListener('scroll', handleProgressScroll);
      ScrollTrigger.getAll().forEach(trigger => trigger.kill());
    };
  }, []);

  return null;
}
